data.value:
decimal _dailyMortAvgSum = 0;
int _dailyMortAvgCount = 0;
decimal _cummMortAvgSum = 0;
int _cummMortAvgCount = 0;
decimal _dailyCullsAvgSum = 0;
int _dailyCullsAvgCount = 0;
decimal _cummCullsAvgSum = 0;
int _cummCullsAvgCount = 0;
decimal _depletionAvgSum = 0;
int _depletionAvgCount = 0;

private void xrTableCell19_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Read current row values safely
decimal femaleStarted = GetCurrentColumnValue("rf_Female_Started") == null
    ? 0
    : Convert.ToDecimal(GetCurrentColumnValue("rf_Female_Started"));

decimal dailyMort = GetCurrentColumnValue("DailyMort") == null
    ? 0
    : Convert.ToDecimal(GetCurrentColumnValue("DailyMort"));

if (femaleStarted != 0)
{
    cell.Text = ((dailyMort / femaleStarted) * 100)
        .ToString("0.##");
}
else
{
    cell.Text = "0.00";
}

}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal femaleStarted = GetCurrentColumnValue("rf_Female_Started") == null
    ? 0
    : Convert.ToDecimal(GetCurrentColumnValue("rf_Female_Started"));

decimal dailyMort = GetCurrentColumnValue("DailyMort") == null
    ? 0
    : Convert.ToDecimal(GetCurrentColumnValue("DailyMort"));

if (femaleStarted != 0)
{
    _dailyMortAvgSum += (dailyMort / femaleStarted) * 100;
    _dailyMortAvgCount++;
}

decimal cummMort = GetCurrentColumnValue("CummMort") == null
    ? 0
    : Convert.ToDecimal(GetCurrentColumnValue("CummMort"));

if (femaleStarted != 0)
{
    _cummMortAvgSum += (cummMort / femaleStarted) * 100;
    _cummMortAvgCount++;
}


decimal dailyCulls = GetCurrentColumnValue("DailCulls") == null
    ? 0
    : Convert.ToDecimal(GetCurrentColumnValue("DailCulls"));

if (femaleStarted != 0)
{
    _dailyCullsAvgSum += (dailyCulls / femaleStarted) * 100;
    _dailyCullsAvgCount++;
}

decimal cummCulls = GetCurrentColumnValue("CummCulls") == null
    ? 0
    : Convert.ToDecimal(GetCurrentColumnValue("CummCulls"));

if (femaleStarted != 0)
{
    _cummCullsAvgSum += (cummCulls / femaleStarted) * 100;
    _cummCullsAvgCount++;
}



if (femaleStarted != 0)
{
    decimal depletion = dailyMort + dailyCulls;
    _depletionAvgSum += (depletion / femaleStarted) * 100;
    _depletionAvgCount++;
}
}

private void xrTableCell17_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

cell.Text = _dailyMortAvgCount > 0
    ? (_dailyMortAvgSum / _dailyMortAvgCount).ToString("0.##") : "0.00";

}

